import { get, isNil } from 'lodash-es';

import type { ColorRuleArgs, Strategies } from './types.js';
import type { ColorRuleProps } from '../types/color-rule.js';
import { getColorPalette } from '../utils/get-color-palette.js';
import { getAccessor } from '../utils/getAccessor.js';
import { getValidColor } from '../utils/getValidColor.js';

export function getSubject<
  T extends ColorRuleArgs[K]['series'][number],
  K extends keyof ColorRuleArgs,
>(this: ReturnType<Strategies[K]>, rule: ColorRuleProps, currentSeries: T) {
  const valueAccessor = rule.valueAccessor;
  if (!valueAccessor || this.forbiddenAccessors.test(valueAccessor)) {
    return currentSeries[this.defaultValueAccessor];
  }
  const accessor = getAccessor(valueAccessor);

  if (accessor) {
    const value = get(currentSeries, accessor);
    if (!isNil(value)) {
      return value;
    }
  }
  return null;
}

export function getColorFromRule(
  rule: ColorRuleProps,
  name: string,
  colorPaletteIndex: number,
) {
  if (rule.colorPalette) {
    return getColorPalette(name, colorPaletteIndex, rule.colorPalette);
  }

  return { Default: getValidColor(rule.color ?? '') };
}

export function* always0() {
  while (true) {
    yield 0;
  }
}

export function* incBy1() {
  let i = -1;
  while (true) {
    i += 1;
    yield i;
  }
}
